mapper.select:
select notice_id, notice_title, notice_content, notice_type, status,
       is_top, publish_time, publisher, community_id, create_by, create_time,
       update_by, update_time, remark
from community_notice


        and notice_title like concat('%', #{noticeTitle}, '%')


        and notice_type = #{noticeType}


        and status = #{status}


        and is_top = #{isTop}


        and community_id = #{communityId}


order by COALESCE(update_time, create_time) desc

mapper.insert:
insert into community_notice (
    notice_title, notice_content, notice_type, status, is_top,
    publish_time, publisher, community_id,
    create_by, create_time, update_by, update_time, remark
) values (
             #{noticeTitle}, #{noticeContent}, #{noticeType}, #{status}, #{isTop},
             #{publishTime}, #{publisher}, #{communityId},
             #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{remark}
         )
